mapper.select:
select s.id, s.shop_name, sc.id as categoryId, sc.category_name, s.address, s.longitude, s.latitude, s.score, s.phone, s.image_url, s.status, s.create_time, s.update_time from tb_shop s left join tb_shop_category sc on s.category_id = sc.id
and s.status = #{status}
and s.category_id = #{categoryId}

select s.id, s.shop_name, s.category_id, sc.category_name, s.address, s.longitude, s.latitude, s.score, s.phone, s.image_url, s.status, s.create_time, s.update_time from tb_shop s left join tb_shop_category sc on s.category_id = sc.id
s.status = 1
and s.category_id = #{categoryId}
and s.shop_name like concat('%',#{shopName},'%')
order by s.score desc limit #{pageStart},#{pageSize}

select s.id as id, count(skr.keyword_id) as match_keywords, s.score as score from tb_shop s left join tb_shop_keyword_relation skr on s.id = skr.shop_id where s.category_id = #{categoryId} and s.status = #{status} and keyword_id in
#{kid}
group by s.id

select s.id as id
from tb_shop s
where s.category_id = #{categoryId}
  and s.status = #{status}
order by score desc
limit #{limit}
